output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?club(COUNT(?event) AS ?wins) WHERE {
  VALUES ?club {
    wd:Q2521385 wd:Q249679 wd:Q2738554
  }
  ?event wdt:P118 wd:Q5070151 ; wdt:P1346 ?club
}
GROUP BY ?club
ORDER BY DESC(?wins)

args.sparql:
SELECT ?premierships
WHERE {
  VALUES ?club { wd:Q2521385 wd:Q249679 wd:Q2738554 }
  ?club wdt:P431 ?premierships
}
ORDER BY DESC(?premierships)
OFFSET 1
LIMIT 1
